          )}
        </AnimatePresence>

        <motion.p
          initial={{ opacity: 0 }}
          animate={{ opacity: 1 }}
          transition={{ delay: 0.5 }}
          className="text-center text-gray-600 text-xs mt-8 flex items-center justify-center gap-2"
        >
          <Sparkles className="w-3 h-3 text-yellow-500" />
          3 interpreta├º├Áes gratuitas inclu├¡das
          <Sparkles className="w-3 h-3 text-yellow-500" />
        </motion.p>
      </div>
    </div>
  );
}

